#!/usr/bin/env python3
from __future__ import annotations
import json
from pathlib import Path
ROOT=Path(__file__).resolve().parents[1];REGISTRY=ROOT/'validation/registry.json';SCRIPT='validate_readiness_refinement.py'
ARTIFACTS=['scripts/validate_readiness_refinement.py','schemas/readiness_refinement.schema.json','experiments/readiness_refinement/results/2026-07-15-local.json','docs/readiness_refinement.md','evidence_quality/model_adequacy_dossiers/readiness-refinement.md','lean/AsiStackProofs/ReadinessRefinement.lean','scripts/validate_readiness_residual_gates.py','scripts/validate_readiness_lifecycle_probe.py','scripts/validate_readiness_check_lifecycle.py']
